class ComprehensiveLogger {
    companion object {
        private const val TAG = "AppLogger"
        private val loggers = ConcurrentHashMap<String, Timber.Tree>()
        private val isInitialized = false
        
        fun init() {
            if (!isInitialized) {
                Timber.plant(object : Timber.Tree() {
                    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
                        when (priority) {
                            Log.VERBOSE -> Log.v(tag, message, t)
                            Log.DEBUG -> Log.d(tag, message, t)
                            Log.INFO -> Log.i(tag, message, t)
                            Log.WARN -> Log.w(tag, message, t)
                            Log.ERROR -> Log.e(tag, message, t)
                        }
                    }
                })
                Timber.plant(Timber.DebugTree())
            }
        }
        
        fun logAuthAttempt(userId: String?, success: Boolean, reason: String? = null) {
            val message = if (success) {
                "AUTH_SUCCESS: User $userId authenticated successfully"
            } else {
                "AUTH_FAILED: User $userId failed authentication - $reason"
            }
            Timber.tag("AUTH").i(message)
        }
        
        fun logDatabaseQuery(query: String, parameters: Map<String, Any>?) {
            val params = parameters?.joinToString(", ") { "${it.key}=${it.value}" } ?: "none"
            val message = "DB_QUERY: $query with parameters [$params]"
            Timber.tag("DATABASE").v(message)
        }
        
        fun logApiRequest(
            url: String,
            method: String,
            headers: Map<String, String>?,
            body: String?
        ) {
            val headerString = headers?.joinToString("\n") { "${it.key}: ${it.value}" } ?: "none"
            val bodyString = body ?: "none"
            val message = "API_REQUEST: $method $url\nHeaders:\n$headerString\nBody: $bodyString"
            Timber.tag("API").v(message)
        }
        
        fun logException(exception: Throwable, context: String = "Unknown") {
            Timber.tag("EXCEPTION").e(exception, "CONTEXT: $context")
        }
        
        fun logInfo(message: String, tag: String = "INFO") {
            Timber.tag(tag).i(message)
        }
        
        fun logWarning(message: String, tag: String = "WARNING") {
            Timber.tag(tag).w(message)
        }
        
        fun logError(message: String, tag: String = "ERROR") {
            Timber.tag(tag).e(message)
        }
    }
}

